const el = document.getElementById('msc'); el.style.cssText = 'width:100%;overflow:auto;min-height:40px'; el.textContent = 'Rendering sequence chart…';
const { default:mscgenjs } = await import('https://cdn.jsdelivr.net/npm/mscgenjs@8.0.0/dist/bundle/index.min.js/+esm');
el.textContent = ''; await new Promise((resolve, reject) => mscgenjs.renderMsc(data.source, { elementId:'msc', inputType:data.inputType ?? 'mscgen', includeSource:false }, (err, svg) => { if (err) { reject(err); return; } if (svg && !el.querySelector('svg')) el.innerHTML = svg; resolve(); }));

