// renderMsc 只能 document.getElementById(light DOM);临时 light 宿主取 SVG 字符串后注入 shadow
const box = document.createElement('div'); box.style.width = '100%'; box.textContent = 'Rendering sequence chart…'; shadowRoot.appendChild(box);
const { default:mscgenjs } = await import('https://cdn.jsdelivr.net/npm/mscgenjs@8.0.0/dist/bundle/index.min.js/+esm');
const tid = 'msc_' + Math.random().toString(36).slice(2);
const tmp = document.createElement('div'); tmp.id = tid; tmp.style.cssText = 'position:absolute;left:-9999px;top:0'; document.body.appendChild(tmp);
await new Promise((resolve, reject) => mscgenjs.renderMsc(data.source, { elementId:tid, inputType:data.inputType ?? 'mscgen', includeSource:false }, (err, svg) => { tmp.remove(); if (err) { box.textContent = String(err); reject(err); return; } box.innerHTML = svg; resolve(); }));

